### Async Generators — Error Propagation and Cleanup

```javascript
// --- Error handling: throw() from outside ---
function* syncGen() {
  try {
    yield 1;
    yield 2;
    yield 3;
  } catch (e) {
    console.log('caught inside generator:', e.message);
    yield 99; // can yield after catching
  }
}

const gen = syncGen();
console.log(gen.next().value); // 1
console.log(gen.throw(new Error('external throw')).value); // caught inside generator: external throw → 99
console.log(gen.next()); // { value: undefined, done: true }

// --- Async generator with proper cleanup ---
async function* streamFromServer(endpoint, signal) {
  const response = await fetch(endpoint, { signal });
  const reader = response.body.getReader();

  try {
    while (true) {
      const { value, done } = await reader.read();
      if (done) break;
      yield new TextDecoder().decode(value);
    }
  } finally {
    // Runs when: loop ends normally, break, return(), or throw()
    reader.releaseLock();
    console.log('Stream reader released');
  }
}

const controller = new AbortController();
const stream = streamFromServer('/sse', controller.signal);

for await (const chunk of stream) {
  console.log(chunk);
  if (chunk.includes('END')) break; // triggers finally in the generator
}

// --- Composing async generators ---
async function* map(iterable, fn) {
  for await (const item of iterable) {
    yield fn(item);
  }
}

async function* filter(iterable, predicate) {
  for await (const item of iterable) {
    if (predicate(item)) yield item;
  }
}

// Pipeline: transform a stream
const processed = filter(
  map(streamFromServer('/data', controller.signal), line => line.trim()),
  line => line.length > 0
);

for await (const line of processed) {
  console.log(line);
}
```

**Common interview trap:** When you `break` out of a `for await...of` loop early, the runtime calls `.return()` on the async generator. This triggers the `finally` block. If you **don't** use `try/finally`, resources (open connections, readers, file handles) won't be released. The `finally` block in async generators is the correct place for cleanup — not `.return()` handlers.

