### Асинхронные генераторы — Распространение ошибок и очистка

```javascript
// --- Обработка ошибок: throw() снаружи ---
function* syncGen() {
  try {
    yield 1;
    yield 2;
    yield 3;
  } catch (e) {
    console.log('поймано внутри генератора:', e.message);
    yield 99; // можно yield после перехвата
  }
}

const gen = syncGen();
console.log(gen.next().value); // 1
console.log(gen.throw(new Error('внешний throw')).value); // поймано внутри генератора: внешний throw → 99
console.log(gen.next()); // { value: undefined, done: true }

// --- Асинхронный генератор с правильной очисткой ---
async function* streamFromServer(endpoint, signal) {
  const response = await fetch(endpoint, { signal });
  const reader = response.body.getReader();

  try {
    while (true) {
      const { value, done } = await reader.read();
      if (done) break;
      yield new TextDecoder().decode(value);
    }
  } finally {
    // Выполняется при: нормальном завершении, break, return(), или throw()
    reader.releaseLock();
    console.log('Reader потока освобождён');
  }
}

const controller = new AbortController();
const stream = streamFromServer('/sse', controller.signal);

for await (const chunk of stream) {
  console.log(chunk);
  if (chunk.includes('END')) break; // запускает finally в генераторе
}

// --- Композиция асинхронных генераторов ---
async function* map(iterable, fn) {
  for await (const item of iterable) {
    yield fn(item);
  }
}

async function* filter(iterable, predicate) {
  for await (const item of iterable) {
    if (predicate(item)) yield item;
  }
}

// Конвейер: трансформация потока
const processed = filter(
  map(streamFromServer('/data', controller.signal), line => line.trim()),
  line => line.length > 0
);

for await (const line of processed) {
  console.log(line);
}
```

**Типичная ошибка на интервью:** Когда ты досрочно выходишь из цикла `for await...of` через `break`, среда выполнения вызывает `.return()` на асинхронном генераторе. Это запускает блок `finally`. Если **не использовать** `try/finally`, ресурсы (открытые соединения, readers, файловые дескрипторы) не будут освобождены. Блок `finally` в асинхронных генераторах — правильное место для очистки.

answer.en:
### Proxy — All 13 Traps: Beyond get and set

Proxy can intercept 13 different fundamental operations on objects.

```javascript
const handler = {
  // Property reads
  get(target, prop, receiver) {
    if (prop === 'secret') throw new Error('Access denied');
    return Reflect.get(target, prop, receiver);
  },

  // Property writes
  set(target, prop, value, receiver) {
    if (typeof value !== typeof target[prop] && target[prop] !== undefined) {
      throw new TypeError(`Type mismatch for ${String(prop)}`);
    }
    return Reflect.set(target, prop, value, receiver);
  },

  // 'in' operator
  has(target, prop) {
    if (prop === 'secret') return false; // hides from 'in' checks
    return Reflect.has(target, prop);
  },

  // delete operator
  deleteProperty(target, prop) {
    if (prop === 'id') throw new Error('Cannot delete id');
    return Reflect.deleteProperty(target, prop);
  },

  // Object.keys(), Object.getOwnPropertyNames()
  ownKeys(target) {
    return Reflect.ownKeys(target).filter(k => k !== 'secret');
  }
};

const obj = new Proxy({ id: 1, name: 'Alice', secret: 'pw123' }, handler);

console.log(obj.name);     // 'Alice'
console.log('secret' in obj); // false — has trap
console.log(Object.keys(obj)); // ['id', 'name'] — secret hidden
// delete obj.id;          // Error: Cannot delete id
// obj.name = 123;         // TypeError: Type mismatch for name

// --- apply trap: intercept function calls ---
function sum(a, b) { return a + b; }
const loggedSum = new Proxy(sum, {
  apply(target, thisArg, args) {
    console.log(`sum(${args.join(', ')}) called`);
    return Reflect.apply(target, thisArg, args);
  }
});
console.log(loggedSum(3, 4)); // logs: sum(3, 4) called → 7

// --- construct trap: intercept new ---
class Point {
  constructor(x, y) { this.x = x; this.y = y; }
}
const SafePoint = new Proxy(Point, {
  construct(target, args) {
    if (args.some(n => typeof n !== 'number')) throw new TypeError('Coordinates must be numbers');
    return Reflect.construct(target, args);
  }
});
new SafePoint(1, 2); // OK
// new SafePoint('a', 2); // TypeError

// --- Revocable proxy: for temporary access ---
const { proxy, revoke } = Proxy.revocable({ data: 'sensitive' }, {});
console.log(proxy.data); // 'sensitive'
revoke();
// proxy.data; // TypeError: Cannot perform 'get' on a proxy that has been revoked
```

**Common interview trap:** The `receiver` parameter in `get` and `set` traps is critical when dealing with getters that use `this`. If you call `Reflect.get(target, prop)` without passing `receiver`, any getter on `target` that uses `this` will get `target` as `this`, not the proxy — breaking patterns where subclasses proxy parent class properties.

