### WeakMap для метаданных DOM-узлов — Реестр событий без утечек

Частый источник утечек памяти в браузерных приложениях: хранение данных с ключами-DOM-узлами в обычном Map или на самом узле.

```javascript
// ПРОБЛЕМА: обычный Map хранит сильные ссылки — DOM-узлы не могут быть GC
const badRegistry = new Map();
function trackElement(el) {
  badRegistry.set(el, { listeners: [], clicks: 0 });
  // Даже после удаления el из DOM и исчезновения всех ссылок,
  // badRegistry держит его живым → утечка памяти
}

// РЕШЕНИЕ: WeakMap — DOM-узлы могут быть собраны при удалении
const elementData = new WeakMap();

function initElement(el) {
  elementData.set(el, {
    listeners: [],
    cleanupFns: [],
    metadata: { createdAt: Date.now() }
  });
}

function addManagedListener(el, event, handler, options) {
  if (!elementData.has(el)) initElement(el);
  const data = elementData.get(el);

  el.addEventListener(event, handler, options);
  // Сохраняем точную ссылку чтобы можно было удалить
  data.listeners.push({ event, handler, options });
  data.cleanupFns.push(() => el.removeEventListener(event, handler, options));
}

function destroyElement(el) {
  const data = elementData.get(el);
  if (!data) return;
  // Удаляем все слушатели перед отсоединением от DOM
  data.cleanupFns.forEach(fn => fn());
  // Не нужно удалять из WeakMap — GC обрабатывает сам
  el.remove();
}

// Использование
const button = document.createElement('button');
addManagedListener(button, 'click', () => console.log('нажато'));
addManagedListener(button, 'mouseenter', () => console.log('наведение'));

destroyElement(button);
// После того как на button нет других ссылок,
// запись WeakMap будет собрана — нет утечки памяти

// WeakSet: отслеживаем инициализированные элементы (без утечки)
const initialized = new WeakSet();

function maybeInit(el) {
  if (initialized.has(el)) return; // уже сделано
  initialized.add(el);
  // настройка...
}
// Когда el удаляется и собирается GC, запись WeakSet исчезает автоматически
```

**Типичная ошибка на интервью:** `WeakMap` и `WeakSet` не имеют свойства `.size` и не итерируемы — это **намеренно**. Если бы можно было перечислять их, GC должен был бы держать все referenced объекты живыми для согласованной итерации. Неитерируемость — то что обеспечивает семантику слабых ссылок. Если нужно отслеживать количество записей, используйте отдельный счётчик с ручным инкрементом/декрементом.

