### Proxy — Глубокая реактивность (отслеживание вложенных объектов)

Поверхностные proxy перехватывают только доступ к свойствам верхнего уровня. Чтобы сделать вложенные объекты реактивными, нужно оборачивать их на лету.

```javascript
function reactive(raw, onChange) {
  // Кэшируем proxy чтобы избежать дублирования
  const proxyCache = new WeakMap();

  function wrap(value) {
    if (value === null || typeof value !== 'object') return value;
    if (proxyCache.has(value)) return proxyCache.get(value);

    const proxy = new Proxy(value, {
      get(target, prop, receiver) {
        const val = Reflect.get(target, prop, receiver);
        // Оборачиваем и вложенные объекты — ленивое создание proxy
        return wrap(val);
      },
      set(target, prop, value, receiver) {
        const oldValue = target[prop];
        const result = Reflect.set(target, prop, value, receiver);
        if (result && oldValue !== value) {
          onChange(prop, value, oldValue);
        }
        return result;
      },
      deleteProperty(target, prop) {
        const hadProp = Reflect.has(target, prop);
        const result = Reflect.deleteProperty(target, prop);
        if (result && hadProp) onChange(prop, undefined, target[prop]);
        return result;
      }
    });

    proxyCache.set(value, proxy);
    return proxy;
  }

  return wrap(raw);
}

const state = reactive(
  { user: { name: 'Alice', address: { city: 'NYC' } } },
  (prop, newVal, oldVal) => console.log(`Изменено: ${String(prop)} = ${JSON.stringify(newVal)}`)
);

console.log(state.user.name); // 'Alice'
state.user.name = 'Bob';      // Изменено: name = "Bob"
state.user.address.city = 'LA'; // Изменено: city = "LA" — вложенное изменение отслежено!

// Это похоже на то как работает система реактивности Vue 3

// --- Замечание о производительности: Reflect.get должен передавать receiver для getter'ов ---
class Config {
  get debug() { return this._debug ?? false; }
  set debug(v) { this._debug = v; }
}

const cfg = reactive(new Config(), console.log);
// Без receiver: 'this' getter'а будет сырой target, а не proxy
// Это ломается когда getter'ы вызывают другие проксированные свойства
```

**Типичная ошибка на интервью:** Без кэширования proxy (`proxyCache`), доступ к одному и тому же вложенному объекту дважды создаёт два разных proxy-экземпляра. Код вроде `state.user === state.user` вернёт `false`, ломая сравнение по идентичности и поиски в `WeakMap`. Vue 3 использует тот же паттерн кэша `WeakMap` для обеспечения стабильности идентичности proxy.

answer.en:
### WeakMap for Memoization and WeakSet for Cycle Detection

```javascript
// --- Memoization with WeakMap (object arguments) ---
// Regular memoization with Map leaks memory if object arguments are transient
const memoCache = new WeakMap();

function memoize(fn) {
  return function(arg) {
    // Only works for object arguments (WeakMap key must be object)
    if (typeof arg !== 'object' || arg === null) return fn(arg);

    if (memoCache.has(arg)) {
      console.log('cache hit');
      return memoCache.get(arg);
    }
    const result = fn(arg);
    memoCache.set(arg, result);
    return result;
  };
}

const expensiveCalc = memoize((config) => {
  // expensive computation based on config object
  return config.values.reduce((sum, n) => sum + n, 0);
});

const cfg1 = { values: [1, 2, 3, 4, 5] };
console.log(expensiveCalc(cfg1)); // 15
console.log(expensiveCalc(cfg1)); // cache hit → 15
// When cfg1 goes out of scope, WeakMap entry is GC'd — no leak

// --- WeakSet for cycle detection in deep clone ---
function deepClone(obj, seen = new WeakSet()) {
  if (obj === null || typeof obj !== 'object') return obj;

  if (seen.has(obj)) {
    throw new Error('Circular reference detected');
  }
  seen.add(obj);

  if (Array.isArray(obj)) {
    return obj.map(item => deepClone(item, seen));
  }

  const clone = {};
  for (const [key, value] of Object.entries(obj)) {
    clone[key] = deepClone(value, seen);
  }
  return clone;
}

const a = { x: 1, nested: { y: 2 } };
console.log(deepClone(a)); // { x: 1, nested: { y: 2 } }

const circular = { name: 'circle' };
circular.self = circular; // circular reference
try {
  deepClone(circular);
} catch (e) {
  console.log(e.message); // 'Circular reference detected'
}

// Why WeakSet and not Set? If the original objects are temporary,
// using Set would prevent their GC during the clone operation.
// With WeakSet, once deepClone returns, the seen set no longer
// holds references to processed objects.
```

**Common interview trap:** The `WeakSet` in `deepClone` is created fresh per call — it's not a global cache. This means different calls don't interfere. But if you made it a closure variable shared across calls, objects from one clone wouldn't be visible to another, which is actually what you want. The key insight: `WeakSet` tracks *identity* (reference equality), not value equality, so `{ x: 1 }` and `{ x: 1 }` are two separate entries.

