### TDZ в классах — Выражения vs Объявления и Производные классы

```javascript
// --- Объявление класса: в TDZ пока не выполнится оператор class ---
try {
  const x = new MyClass(); // ReferenceError: Cannot access 'MyClass' before initialization
} catch (e) { console.log(e.message); }

class MyClass {
  constructor() { this.value = 42; }
}

const y = new MyClass(); // Здесь OK

// --- Выражение класса: имя доступно только внутри тела класса ---
const Foo = class FooInternal {
  getType() {
    return FooInternal.name; // 'FooInternal' — доступно внутри
  }
};

const f = new Foo();
console.log(f.getType()); // 'FooInternal'
// console.log(FooInternal); // ReferenceError — имя не в внешней области

// --- Производный класс: super() должен завершиться до доступа к `this` ---
class Base {
  constructor() {
    this.base = 'инициализирован';
  }
}

class Child extends Base {
  constructor() {
    // `this` в TDZ здесь — super() ещё не выполнен
    // console.log(this.base); // ReferenceError!
    super(); // инициализирует 'this'
    console.log(this.base); // 'инициализирован' — теперь безопасно
    this.child = 'дочернее свойство';
  }
}

new Child();

// --- Поля класса и TDZ ---
class Example {
  // Публичные поля инициализируются по порядку на экземпляре
  x = 1;
  y = this.x + 1; // допустимо: x уже инициализирован
  z = this.w;     // undefined: w ещё не определён (но не TDZ — просто undefined)
  w = 4;
}

const e = new Example();
console.log(e.x, e.y, e.z, e.w); // 1, 2, undefined, 4

// --- Статические поля класса ---
class Config {
  static DEFAULT_TIMEOUT = 5000;
  static create() { return new Config(Config.DEFAULT_TIMEOUT); }
  constructor(timeout) { this.timeout = timeout; }
}
// Статические поля инициализируются при вычислении класса, не при создании экземпляра
```

**Типичная ошибка на интервью:** Объявления `class` НЕ как объявления `function`. `function greet() {}` полностью поднимается — можно вызвать до объявления. `class Foo {}` поднимается в область видимости (поэтому повторное объявление той же области — ошибка) но его инициализатор не выполняется до оператора class — остаётся в TDZ. Вот почему `new Foo()` до `class Foo {}` бросает, хотя привязка `Foo` технически существует.

