### Abstract Relational Comparison vs Abstract Equality — Different Coercion Algorithms

```javascript
// == (Abstract Equality Comparison) — special rules:
// - null == undefined → true (special case, no coercion)
// - null == anything_else → false (special case)
// - NaN == NaN → false (always)
// - Otherwise: ToPrimitive then ToNumber for mixed types

console.log(null == undefined);  // true — special pair
console.log(null == 0);          // false — null special case
console.log(null == '');         // false
console.log(null == false);      // false

// > < >= <= (Abstract Relational Comparison) — different algorithm:
// Converts BOTH sides to primitives first, then:
// - If both are strings: lexicographic comparison
// - Otherwise: ToNumber for both

console.log(null > 0);   // false (null → 0; 0 > 0 is false)
console.log(null < 0);   // false (null → 0; 0 < 0 is false)
console.log(null >= 0);  // true  (null → 0; 0 >= 0 is true!) ← the famous trap
console.log(null <= 0);  // true  (null → 0; 0 <= 0 is true!)
console.log(null == 0);  // false ← but == uses special null rule, NOT ToNumber

// So: null is neither > 0 nor < 0 nor == 0, but null >= 0 is true!
// This is NOT a bug — it's a spec-defined inconsistency

// String comparison is lexicographic, not numeric!
console.log('10' > '9');   // false! '1' < '9' in char codes
console.log(10 > 9);       // true
console.log('10' > 9);     // true (mixed types → both become numbers)

// NaN comparisons are always false
console.log(NaN > 0);      // false
console.log(NaN < 0);      // false
console.log(NaN >= 0);     // false
console.log(NaN == NaN);   // false (use Number.isNaN() instead)

// Practical implication: never check age in a valid range like this:
function isValidAge(age) {
  // WRONG: null >= 0 is true!
  return age >= 0 && age <= 150;
}
console.log(isValidAge(null)); // true — bug!

function isValidAgeSafe(age) {
  // RIGHT: explicit null/undefined check first
  return typeof age === 'number' && age >= 0 && age <= 150;
}
console.log(isValidAgeSafe(null)); // false
```

**Common interview trap:** The `null >= 0` being `true` while `null == 0` is `false` trips many developers. These use **different algorithms** from the spec: relational operators (`>`, `<`, `>=`, `<=`) always convert to numbers (so `null` → `0`), while abstract equality (`==`) has a special case where `null` only equals `undefined` and nothing else.

answer.ru:
### Абстрактное реляционное сравнение vs Абстрактное равенство — Разные алгоритмы приведения

```javascript
// == (Abstract Equality Comparison) — специальные правила:
// - null == undefined → true (специальный случай, без приведения)
// - null == что-угодно_другое → false (специальный случай)
// - NaN == NaN → false (всегда)
// - Иначе: ToPrimitive затем ToNumber для смешанных типов

console.log(null == undefined);  // true — специальная пара
console.log(null == 0);          // false — специальный случай null
console.log(null == '');         // false
console.log(null == false);      // false

// > < >= <= (Abstract Relational Comparison) — другой алгоритм:
// Сначала преобразует ОБЕ стороны в примитивы, затем:
// - Если обе строки: лексикографическое сравнение
// - Иначе: ToNumber для обеих

console.log(null > 0);   // false (null → 0; 0 > 0 ложно)
console.log(null < 0);   // false (null → 0; 0 < 0 ложно)
console.log(null >= 0);  // true  (null → 0; 0 >= 0 истинно!) ← знаменитая ловушка
console.log(null <= 0);  // true  (null → 0; 0 <= 0 истинно!)
console.log(null == 0);  // false ← но == использует специальное правило null, НЕ ToNumber

// Итак: null не больше 0, не меньше 0, не равен 0, но null >= 0 истинно!
// Это НЕ баг — это несогласованность определённая спецификацией

// Сравнение строк лексикографическое, а не числовое!
console.log('10' > '9');   // false! '1' < '9' по кодам символов
console.log(10 > 9);       // true
console.log('10' > 9);     // true (смешанные типы → оба становятся числами)

// Сравнения NaN всегда false
console.log(NaN > 0);      // false
console.log(NaN < 0);      // false
console.log(NaN >= 0);     // false
console.log(NaN == NaN);   // false (используйте Number.isNaN())

// Практическое следствие: никогда не проверяйте возраст так:
function isValidAge(age) {
  // НЕВЕРНО: null >= 0 истинно!
  return age >= 0 && age <= 150;
}
console.log(isValidAge(null)); // true — баг!

function isValidAgeSafe(age) {
  // ВЕРНО: сначала явная проверка на null/undefined
  return typeof age === 'number' && age >= 0 && age <= 150;
}
console.log(isValidAgeSafe(null)); // false
```

**Типичная ошибка на интервью:** Ситуация когда `null >= 0` истинно, а `null == 0` ложно, путает многих разработчиков. Они используют **разные алгоритмы** из спецификации: реляционные операторы (`>`, `<`, `>=`, `<=`) всегда конвертируют в числа (так `null` → `0`), а абстрактное равенство (`==`) имеет специальный случай где `null` равен только `undefined` и больше ничему.

